import React from "react";
import { InputSwitch, type InputSwitchProps } from "primereact/inputswitch";
import { useSeparator } from "../../../factory";
import type { IKitsInputSwitch } from "@lmb-it/kitsconcerto-types";
import {KitsContainer} from "../../../_compat";
import {ClHelper} from "../../helpers/Functions";
import {useFormInputController} from "../../helpers/useFormInputController";
import {useComponentDefaults, useResolvedStyle} from "../../../hooks";
import CheckboxButton from "../../controls/Checkbox/checkbox";

const KitsInputSwitch: React.FC<IKitsInputSwitch> = ({ ref, ...rawProps }) => {
    const {mergedProps: props, themeStyle, elementStyles} = useComponentDefaults('Switch', rawProps);
    const resolvedThemeStyle = useResolvedStyle(themeStyle);
    const resolvedRootStyle = useResolvedStyle(elementStyles?.root || {});

    const {
        id,
        label,
        helperText,
        errors,
        invalid,
        required,
        disabled,
        inputSize,
        localProps,
        value,
        checked,
        defaultValue,
        onChange,
        attached,
        displayAs,
        direction,
        containerStyle,
        ...rest
    } = props;

    const isCheckbox = displayAs === 'checkbox';

    // Controlled value: explicit `checked` or `value` prop
    const controlledValue = typeof checked === 'boolean' ? checked
        : typeof value === 'boolean' ? value
        : undefined;

    // Default value: only used when neither checked nor value is set (uncontrolled)
    const resolvedDefault = typeof defaultValue === 'boolean' ? defaultValue : false;

    // useFormInputController returns (displayValue, emitChange) handling controlled/uncontrolled
    const { value: displayValue, emitChange } =
        useFormInputController<boolean>({
            value: controlledValue,
            defaultValue: resolvedDefault,
            onChange,
        });

    const { nativeProps } = useSeparator<InputSwitchProps>({ ...rest, ...(localProps as any) });

    const clState = ClHelper({
        inputSize: inputSize ?? '',
        isChecked: !!displayValue,
        isInvalid: false,
        isDisabled: !!disabled,
    });

    const className = [nativeProps.className, clState].filter(Boolean).join(' ');

    // Resolve display label text for checkbox mode
    const labelText = typeof label === 'string' ? label
        : typeof label === 'object' && label !== null && 'text' in label ? (label as any).text
        : undefined;

    const Element = isCheckbox
        ? <CheckboxButton
            item={{
                value: true,
                label: labelText ?? '',
                withBulbs: true,
                labelPosition: 'right',
            }}
            selected={!!displayValue}
            disabled={disabled}
            isInvalid={invalid}
            onToggle={() => emitChange(!displayValue)}
        />
        : <InputSwitch
            {...nativeProps}
            className={className}
            style={resolvedRootStyle || (Object.keys(resolvedThemeStyle).length ? resolvedThemeStyle : undefined)}
            ref={ref as any}
            checked={!!displayValue}
            disabled={disabled}
            onChange={(e) => emitChange(e.target.value)}
        />;

    if (attached) {
        return Element;
    }

    const isRow = direction === 'row';

    if (isRow && !isCheckbox) {
        const rowLabelText = typeof label === 'string' ? label
            : typeof label === 'object' && label !== null && 'text' in label ? (label as any).text
            : undefined;

        return (
            <div style={{ display: 'flex', flexDirection: 'column', width: '100%' }}>
                <div style={{
                    display: 'flex',
                    flexDirection: 'row',
                    justifyContent: 'space-between',
                    alignItems: 'center',
                    width: '100%',
                }}>
                    {rowLabelText && (
                        <label
                            htmlFor={id}
                            style={{
                                cursor: disabled ? 'default' : 'pointer',
                                opacity: disabled ? 0.6 : 1,
                            }}
                        >
                            {rowLabelText}
                        </label>
                    )}
                    {Element}
                </div>
                {helperText && (
                    <small style={{ color: 'var(--text-color-secondary)', marginTop: '0.25rem' }}>
                        {typeof helperText === 'string' ? helperText : helperText}
                    </small>
                )}
                {errors && (
                    <small style={{ color: 'var(--kits-danger)', marginTop: '0.25rem' }}>
                        {errors}
                    </small>
                )}
            </div>
        );
    }

    return (
        <KitsContainer
            id={id}
            required={required}
            helperText={helperText}
            errors={errors}
            invalid={invalid}
            label={isCheckbox ? undefined : label}
            disabled={disabled}
            inputSize={inputSize}
            additionalClassName={'unfocusable-element'}
            bare
        >
            {Element}
        </KitsContainer>
    );
};

export default KitsInputSwitch;
